mapper.select:


    pd.del_flag = '0'
     and pd.production_year = #{productionYear}
     and pd.batch_id = #{batchId}
     and COALESCE(t.product, pd.product) = #{product}
     and pd.task_id = #{taskId}
     and COALESCE(t.task_code, pd.task_no) like concat('%', #{taskCode}, '%')
     and COALESCE(t.task_name, pd.task_name) like concat('%', #{taskName}, '%')
     and pd.problem_no like concat('%', #{problemNo}, '%')
     and pd.problem_level = #{problemLevel}
     and pd.current_status = #{currentStatus}
     and pd.whether_defect = #{whetherDefect}
     and pd.whether_overtime = #{whetherOvertime}
     and pd.whether_pro_recurrence = #{whetherProRecurrence}
     and pd.whether_att_required = #{whetherAttRequired}
     and pd.solution_time_over_one_day = #{solutionTimeOverOneDay}
     and uc.nick_name like concat('%', #{creatorName}, '%')
     and pd.submit_date >= #{submitDateStart}
     and pd.submit_date <= #{submitDateEnd}
     and pd.create_time >= #{createDateStart}
     and pd.create_time <= concat(#{createDateEnd}, ' 23:59:59')


        and (pd.dept_id = #{deptId}
             or pd.dept_id in (select dept_id from sys_dept where find_in_set(#{deptId}, ancestors) > 0))


order by pd.create_time desc, pd.problem_id desc

select count(1) from pm_prolist_defect
where problem_no = #{problemNo} and del_flag = '0'
 and problem_id != #{problemId}

select t.task_id as taskId, t.task_code as taskCode, t.task_name as taskName, t.product as product
from pm_task t
left join pm_project p on t.project_id = p.project_id
where t.production_year = #{productionYear}
  and t.batch_id = #{batchId}

  and (p.project_dept = #{deptId}
       or p.project_dept in (select dept_id from sys_dept where find_in_set(#{deptId}, ancestors) > 0))

order by t.task_code

select p.project_dept from pm_task t
left join pm_project p on t.project_id = p.project_id
where t.task_id = #{taskId}
